102	 *
103	 * Runs at most once per worker process — the temp file is reused.
104	 */
105	function ensureGoogleApplicationCredentialsFromJson(): void {
106	  const json = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON;
107	  if (!json) return;
108	  if (process.env.GOOGLE_APPLICATION_CREDENTIALS) return;
109	  const tmpPath = join(tmpdir(), 'oracle-gcp-application-default-credentials.json');
110	  if (!existsSync(tmpPath)) {
111	    writeFileSync(tmpPath, json, { mode: 0o600 });
112	  }
113	  process.env.GOOGLE_APPLICATION_CREDENTIALS = tmpPath;
114	}
