122	  constructor(opts: VertexGeminiAdapterOptions = {}) {
123	    ensureGoogleApplicationCredentialsFromJson();
124	    const project = opts.project ?? process.env.GOOGLE_CLOUD_PROJECT;
125	    const location =
126	      opts.location ?? process.env.GOOGLE_CLOUD_LOCATION ?? 'us-central1';
127	    if (!project) {
128	      throw new Error(
129	        'VertexGeminiAdapter: GOOGLE_CLOUD_PROJECT is not set. ' +
130	          'Set it in .env.local or pass {project} explicitly.',
131	      );
132	    }
133	    this.client = new GoogleGenAI({ vertexai: true, project, location });
