136	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
137	    const { plan, route, providerOptions } = args;
138	    const { systemPrompt, prefixContext, dynamicInput } = splitPlanForCaching(plan);
139	    const userMessage = [prefixContext, dynamicInput].filter(Boolean).join('\n\n');
140	    await this.cleanupExpiredExplicitCaches();
141	    await this.cleanupExpiredPersistentCaches();
142	    const contents = this.buildContents(userMessage, providerOptions);
143	    const explicitCache = shouldDisableCache(providerOptions)
144	      ? null
145	      : await this.prepareExplicitCacheForText(plan, route.modelId, systemPrompt, contents, providerOptions);
146	    const callStartedAt = Date.now();
147	
148	    const response = await this.client.models.generateContent({
149	      model: route.modelId,
150	      contents: explicitCache?.contentsForRequest ?? contents,
151	      config: {
152	        systemInstruction: explicitCache?.omitSystemInstruction
153	          ? undefined
154	          : systemPrompt || undefined,
155	        temperature:
156	          typeof providerOptions?.temperature === 'number'
157	            ? providerOptions.temperature
158	            : undefined,
159	        ...(explicitCache?.cacheName ? { cachedContent: explicitCache.cacheName } : {}),
160	        ...vertexThinkingConfig(route.reasoningEffort),
161	      },
162	    });
163	    const latencyMs = Date.now() - callStartedAt;
164	    await this.recordSuccessfulExplicitCacheReuse(explicitCache);
165	    return {
166	      text: response.text ?? '',
167	      usage: this.normalizeUsage(response, latencyMs),
168	      rawResponse: response,
169	    };
170	  }
171	
172	  async generateObject<TSchema, TOutput>(
173	    args: GenerateObjectArgs<TSchema>,
174	  ): Promise<OracleObjectResult<TOutput>> {
175	    const { plan, route, schema, providerOptions } = args;
176	    const { systemPrompt, prefixContext, dynamicInput } = splitPlanForCaching(plan);
177	    const userMessage = [prefixContext, dynamicInput].filter(Boolean).join('\n\n');
178	    const jsonSchema = zodToJsonSchema(schema);
179	    await this.cleanupExpiredExplicitCaches();
180	    await this.cleanupExpiredPersistentCaches();
181	    const explicitCache = shouldDisableCache(providerOptions)
182	      ? null
183	      : await this.prepareExplicitCacheForObject(
184	          plan,
185	          route.modelId,
186	          systemPrompt,
187	          prefixContext,
188	          dynamicInput,
189	          providerOptions,
190	        );
191	    const callStartedAt = Date.now();
192	
193	    const response = await this.client.models.generateContent({
194	      model: route.modelId,
195	      contents: [{ role: 'user', parts: [{ text: explicitCache?.requestUserMessage ?? userMessage }] }],
196	      config: {
197	        systemInstruction: explicitCache?.omitSystemInstruction
198	          ? undefined
199	          : systemPrompt || undefined,
200	        temperature: 0.1,
201	        responseMimeType: 'application/json',
202	        // responseJsonSchema accepts standard JSON Schema as of @google/genai 2.6.
203	        responseJsonSchema: jsonSchema as unknown,
204	        ...(explicitCache?.cacheName ? { cachedContent: explicitCache.cacheName } : {}),
205	        ...vertexThinkingConfig(route.reasoningEffort),
206	      },
207	    });
208	    const latencyMs = Date.now() - callStartedAt;
209	    await this.recordSuccessfulExplicitCacheReuse(explicitCache);
210	    const text = response.text ?? '';
211	    const parsed = parseJsonOrRaw(text);
212	    // Best-effort runtime validation if a Zod schema was supplied — gives the
213	    // caller a typed error rather than silently passing through malformed output.
214	    const validated = tryZodParse<TOutput>(schema, parsed);
215	    return {
216	      object: (validated ?? parsed) as TOutput,
217	      usage: this.normalizeUsage(response, latencyMs),
218	      rawResponse: response,
219	    };
220	  }
