332	  private async prepareExplicitCacheForObject(
333	    plan: OraclePromptPlan,
334	    modelId: string,
335	    systemPrompt: string,
336	    prefixContext: string,
337	    dynamicInput: string,
338	    providerOptions?: Record<string, unknown>,
339	  ): Promise<{
340	    cacheName?: string;
341	    omitSystemInstruction: boolean;
342	    requestUserMessage?: string;
343	    lifecycleHandle?: CacheLifecycleHandle;
344	  } | null> {
345	    const hints = getCacheHints(providerOptions);
346	    const fileCache = await this.prepareExplicitFileCache(plan, modelId, systemPrompt, providerOptions);
347	    if (fileCache) {
348	      return {
349	        cacheName: fileCache.name,
350	        omitSystemInstruction: true,
351	        requestUserMessage: fileCache.dynamicInput,
352	        lifecycleHandle: fileCache.lifecycleHandle,
353	      };
354	    }
355	    const stableTokens = estimatePlanStableTokens(plan);
356	    const prefixTokens = estimateTextTokens(prefixContext);
357	    const cacheableTokenEstimate = stableTokens + prefixTokens;
358	    if (
359	      !(hints?.preferExplicitCache === true || cacheableTokenEstimate >= 2048) ||
360	      (!systemPrompt && !prefixContext)
361	    ) {
362	      return null;
363	    }
364	    const explicitCache = await this.getOrCreateExplicitCache({
365	      modelId,
366	      systemInstruction: systemPrompt || undefined,
367	      contents: prefixContext
368	        ? [{ role: 'user', parts: [{ text: prefixContext }] }]
369	        : [],
370	      ttlSeconds: pickVertexCacheTtlSeconds(plan.taskType, providerOptions),
371	      cacheKey: hashCacheKey([
372	        modelId,
373	        plan.metadata.stablePrefixHash,
374	        plan.metadata.semiStableContextHash,
375	        plan.metadata.retrievedContextHash,
376	        'object-prefix',
377	      ]),
378	      sourceHash: hashCacheKey([
379	        plan.metadata.stablePrefixHash,
380	        plan.metadata.semiStableContextHash,
381	        plan.metadata.retrievedContextHash,
382	        'object-prefix',
383	      ]),
384	      sourceTokenEstimate: estimateTextTokens([systemPrompt, prefixContext].filter(Boolean).join('\n\n')),
385	      sourceDescription:
386	        hints?.sourceDescription ?? `${plan.taskType} structured-output prefix`,
387	      expectedReuseCount: Math.max(1, hints?.expectedReuseCount ?? 1),
388	      latestPlannedReuseStep: hints?.latestPlannedReuseStep ?? plan.taskType,
389	      cleanupOwner: hints?.cleanupOwner,
390	      createdByJobRunId: hints?.createdByJobRunId,
391	      persistRecord: hints?.persistProviderCacheRecord === true,
392	    });
393	    if (!explicitCache) return null;
394	    return {
395	      cacheName: explicitCache.name,
396	      omitSystemInstruction: true,
397	      requestUserMessage: dynamicInput,
398	      lifecycleHandle: explicitCache.lifecycleHandle,
399	    };
400	  }
