402	  private async getOrCreateExplicitCache(input: {
403	    modelId: string;
404	    systemInstruction?: string;
405	    contents: Content[];
406	    ttlSeconds: number;
407	    cacheKey: string;
408	    sourceHash: string;
409	    sourceTokenEstimate: number;
410	    sourceDescription: string;
411	    expectedReuseCount: number;
412	    latestPlannedReuseStep?: string;
413	    cleanupOwner?: string;
414	    createdByJobRunId?: string;
415	    persistRecord: boolean;
416	    providerMetadataJson?: unknown;
417	  }): Promise<{ name: string; lifecycleHandle?: CacheLifecycleHandle } | null> {
418	    const existing = this.explicitCacheByKey.get(input.cacheKey);
419	    if (existing && existing.expiresAtMs > Date.now()) {
420	      return { name: existing.name, lifecycleHandle: existing.lifecycleHandle };
421	    }
422	
423	    if (input.persistRecord) {
424	      const persisted = await this.getPersistedExplicitCache(input);
425	      if (persisted) return persisted;
426	    }
427	    try {
428	      const created = await this.client.caches.create({
429	        model: input.modelId,
430	        config: {
431	          contents: input.contents,
432	          systemInstruction: input.systemInstruction,
433	          displayName: `oracle-${input.cacheKey.slice(0, 32)}`,
434	          ttl: `${Math.max(60, input.ttlSeconds)}s`,
435	        },
436	      });
437	      const name = created.name;
438	      if (!name) return null;
439	      const expiresAtMs = Date.now() + Math.max(60, input.ttlSeconds) * 1000;
440	      const lifecycleHandle = input.persistRecord
441	        ? await recordCacheCreation({
442	            db: getDirectDb(),
443	            provider: 'vertex',
444	            cacheKind: 'explicit',
445	            sourceHash: input.sourceHash,
446	            sourceTokenEstimate: input.sourceTokenEstimate,
447	            sourceDescription: input.sourceDescription,
448	            providerResourceName: name,
449	            expectedReuseCount: input.expectedReuseCount,
450	            latestPlannedReuseStep: input.latestPlannedReuseStep,
451	            hardExpirationAt: new Date(expiresAtMs),
452	            cleanupOwner: input.cleanupOwner,
453	            createdByJobRunId: input.createdByJobRunId,
454	            providerMetadataJson: input.providerMetadataJson,
455	          })
456	        : undefined;
457	      this.explicitCacheByKey.set(input.cacheKey, {
458	        name,
459	        expiresAtMs,
460	        includesSystemInstruction: !!input.systemInstruction,
461	        lifecycleHandle,
462	      });
463	      return { name, lifecycleHandle };
464	    } catch (err) {
465	      console.warn(
466	        `[VertexGeminiAdapter] explicit cache create failed; falling back to implicit cache: ${
467	          err instanceof Error ? err.message : String(err)
468	        }`,
469	      );
470	      return null;
471	    }
472	  }
473	
474	  private async prepareExplicitFileCache(
475	    plan: OraclePromptPlan,
476	    modelId: string,
477	    systemPrompt: string,
478	    providerOptions?: Record<string, unknown>,
479	  ): Promise<{
480	    name: string;
481	    dynamicInput: string;
482	    lifecycleHandle?: CacheLifecycleHandle;
483	  } | null> {
484	    const hints = getCacheHints(providerOptions);
485	    const fileSource = hints?.vertexFileCacheSource;
486	    if (!fileSource || hints?.preferExplicitCache !== true) return null;
487	
488	    const { dynamicInput } = splitPlanForCaching(plan);
489	    const gcsUpload = await this.ensureVertexCacheFileUri(fileSource);
490	    if (!gcsUpload?.fileUri) return null;
491	
492	    const explicitCache = await this.getOrCreateExplicitCache({
493	      modelId,
494	      systemInstruction: systemPrompt,
495	      contents: [
496	        {
497	          role: 'user',
498	          parts: [
499	            {
500	              fileData: {
501	                fileUri: gcsUpload.fileUri,
502	                mimeType: fileSource.mimeType,
503	              },
504	            },
505	          ],
506	        },
507	      ],
508	      ttlSeconds: pickVertexCacheTtlSeconds(plan.taskType, providerOptions),
509	      cacheKey: hashCacheKey([
510	        modelId,
511	        plan.metadata.stablePrefixHash,
512	        fileSource.sourceHash ?? fileSource.gcsUri ?? fileSource.localPath,
513	        'file-backed',
514	      ]),
515	      sourceHash: fileSource.sourceHash ??
516	        hashCacheKey([plan.metadata.stablePrefixHash, fileSource.gcsUri ?? fileSource.localPath, 'file-backed']),
517	      sourceTokenEstimate: estimatePlanStableTokens(plan),
518	      sourceDescription: hints?.sourceDescription ?? `${plan.taskType} file-backed cache`,
519	      expectedReuseCount: Math.max(1, hints?.expectedReuseCount ?? 1),
520	      latestPlannedReuseStep: hints?.latestPlannedReuseStep ?? plan.taskType,
521	      cleanupOwner: hints?.cleanupOwner,
522	      createdByJobRunId: hints?.createdByJobRunId,
523	      persistRecord: hints?.persistProviderCacheRecord === true,
524	      providerMetadataJson: gcsUpload.objectName
525	        ? {
526	            uploadedGcsUri: gcsUpload.fileUri,
527	            uploadedObjectName: gcsUpload.objectName,
528	            mimeType: fileSource.mimeType,
529	          }
530	        : undefined,
531	    });
532	    if (!explicitCache) return null;
533	    return {
534	      name: explicitCache.name,
535	      dynamicInput,
536	      lifecycleHandle: explicitCache.lifecycleHandle,
537	    };
538	  }
539	
540	  private async ensureVertexCacheFileUri(fileSource: VertexFileCacheSource): Promise<{
541	    fileUri: string;
542	    objectName?: string;
543	  } | null> {
544	    if (fileSource.gcsUri) return { fileUri: fileSource.gcsUri };
545	    if (!fileSource.localPath) return null;
546	    const bucketName = process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET;
547	    if (!bucketName) {
548	      console.warn('[VertexGeminiAdapter] GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET is unset; skipping file-backed cache path');
549	      return null;
550	    }
551	    const prefix = process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_PREFIX ?? 'oracle-context-cache';
552	    const objectName = `${prefix}/${fileSource.sourceHash ?? hashCacheKey([fileSource.localPath, fileSource.fileName])}-${fileSource.fileName ?? 'source'}`;
553	    const storage = this.getStorageClient();
554	    await storage.bucket(bucketName).upload(fileSource.localPath, {
555	      destination: objectName,
556	      metadata: {
557	        contentType: fileSource.mimeType,
558	      },
559	    });
560	    return {
561	      fileUri: `gs://${bucketName}/${objectName}`,
562	      objectName,
563	    };
564	  }
565	
566	  private getStorageClient(): Storage {
567	    if (!this.storageClient) {
568	      this.storageClient = new Storage();
569	    }
570	    return this.storageClient;
571	  }
