1	/**
2	 * Vertex file-backed cache + multi-turn regression gate.
3	 *
4	 * Run with:
5	 *   pnpm --filter @oracle/ai exec tsx src/__verify__/vertex-file-cache-multiturn.ts
6	 *
7	 * Proves the chat-attachment file-cache enhancement (v1):
8	 *   - When a `vertexFileCacheSource` is supplied with `preferExplicitCache`,
9	 *     the adapter creates a Gemini cachedContent from systemInstruction + a
10	 *     gs:// fileData part (the document corpus).
11	 *   - The generateContent request references that cache via `cachedContent`,
12	 *     omits `systemInstruction` (it lives in the cache), AND preserves the
13	 *     FULL multi-turn conversation as live contents — the regression this
14	 *     gate exists to prevent (the old file-cache path collapsed the request
15	 *     to a single dynamicInput turn, which would erase chat history).
16	 *   - The structured-output path (generateObject) is intentionally NOT
17	 *     exercised here — it keeps its single-turn shape for extraction.
18	 *
19	 * No network / DB: the GoogleGenAI client + Storage client are stubbed and
20	 * the cache-lifecycle DB sweepers are no-op'd. persistProviderCacheRecord is
21	 * false so no provider_cached_content rows are touched.
22	 *
23	 * This file is in __verify__ so it is never picked up as a production export.
24	 */
25	
26	import { VertexGeminiAdapter, getOracleRoute, type OracleModelRoute } from '../index';
27	import { getContextCompiler } from '../context/context-compiler';
28	import { makeBlock } from '../index';
29	
30	function assert(cond: unknown, msg: string): asserts cond {
31	  if (!cond) {
32	    console.error(`✗ ${msg}`);
33	    process.exit(1);
34	  }
35	  console.log(`✓ ${msg}`);
36	}
37	
38	async function main() {
39	  console.log('Vertex file-cache multi-turn gate\n');
40	
41	  // The adapter constructor needs a project; GoogleGenAI does no network I/O
42	  // at construction. The GCS bucket env activates the file-backed cache path.
43	  process.env.GOOGLE_CLOUD_PROJECT ??= 'verify-project';
44	  process.env.GOOGLE_CLOUD_LOCATION ??= 'us-central1';
45	  process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET ??= 'verify-bucket';
46	
47	  const route = getOracleRoute('vertex_gemini_2_5_flash_extraction_primary') as OracleModelRoute;
48	  assert(route?.provider === 'vertex', 'resolved a Vertex route');
49	
50	  // Two stable chat blocks, mirroring the interview chat route.
51	  const blocks = [
52	    makeBlock({
53	      id: 'oracle-system',
54	      label: 'Oracle interview system prompt',
55	      kind: 'stable_system',
56	      content: 'You are the Oracle. Answer from approved knowledge.',
57	      reasonIncluded: 'system prompt',
58	    }),
59	    makeBlock({
60	      id: 'turn-context',
61	      label: 'Per-turn retrieval bundle',
62	      kind: 'retrieved_context',
63	      content: 'CONTEXT: speaking with Albert.',
64	      reasonIncluded: 'turn context',
65	    }),
66	  ];
67	  const plan = getContextCompiler().compile({
68	    taskType: 'interview_chat',
69	    routeId: route.routeId,
70	    promptVersion: 'file-cache-gate',
71	    blocks,
72	  });
73	
74	  // Multi-turn conversation (the document is in the cache, so turns are text).
75	  const messages = [
76	    { role: 'user' as const, content: '[Oracle runtime context]\nCONTEXT: speaking with Albert.' },
77	    { role: 'user' as const, content: 'What does the spec say about returns?' },
78	    { role: 'assistant' as const, content: 'Let me check the document.' },
79	    { role: 'user' as const, content: 'SECOND_TURN_MARKER: summarize section 4 of the PDF.' },
80	  ];
81	
82	  // ── Stub the provider client + storage; neutralize DB sweepers ──────────
83	  const createCalls: Array<Record<string, any>> = [];
84	  const generateCalls: Array<Record<string, any>> = [];
85	  const adapter = new VertexGeminiAdapter();
86	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
87	  const anyAdapter = adapter as any;
88	  anyAdapter.client = {
89	    caches: {
90	      create: async (cfg: Record<string, any>) => {
91	        createCalls.push(cfg);
92	        return { name: 'projects/p/locations/l/cachedContents/CACHE123' };
93	      },
94	      get: async () => ({}),
95	      delete: async () => ({}),
96	    },
97	    models: {
98	      generateContent: async (req: Record<string, any>) => {
99	        generateCalls.push(req);
100	        return { text: 'answer', usageMetadata: {} };
101	      },
102	    },
103	  };
104	  anyAdapter.storageClient = {
105	    bucket: () => ({
106	      upload: async () => [{}],
107	      file: () => ({ delete: async () => {} }),
108	    }),
109	  };
110	  // Sweepers hit getDirectDb(); no DB in this gate.
111	  anyAdapter.cleanupExpiredExplicitCaches = async () => {};
112	  anyAdapter.cleanupExpiredPersistentCaches = async () => {};
113	
114	  const result = await adapter.generateText({
115	    plan,
116	    route,
117	    providerOptions: {
118	      messages,
119	      cache: {
120	        preferExplicitCache: true,
121	        persistProviderCacheRecord: false, // no DB
122	        cacheTtlSeconds: 30 * 60,
