).sort((a, b) => (a.promptPer1M ?? Infinity) - (b.promptPer1M ?? Infinity));
```

Uses `meetsStageReq()` from the shared stage-requirements module.

---

### **7. MODEL LIST API**

**File:** `/apps/web/app/api/admin/models/route.ts`

```typescript
// GET /api/admin/models?stage=interview|extraction|synthesis|general
```

**Logic** (lines 82-115):

```typescript
const stage = parseStage(req);  // defaults to 'interview'
const db = getDirectDb();
const catalog = await loadModelCatalog(db);  // reads model_capabilities table

if (stage === 'general') {
  return NextResponse.json({ models: catalog.map(capabilityToModelInfo) });
}

const poolKey = MODEL_POOL_SETTING_KEYS[stage];
const poolRow = await db.select({ value: settings.value })
  .from(settings)
  .where(eq(settings.key, poolKey))
  .limit(1);

const pool: string[] = Array.isArray(poolRow[0]?.value) 
  ? (poolRow[0]!.value as string[]) 
  : [];

if (pool.length > 0) {
  return NextResponse.json({
    models: catalog.filter((c) => poolSet.has(c.id)).map(capabilityToModelInfo),
  });
}

return NextResponse.json({ models: catalog.map(capabilityToModelInfo) });
```

**Returns:** `{ models: ModelInfo[] }` where each model has:
- `id`, `name`, `provider`, `contextLength`
- **Capabilities:** `vision`, `thinking`, `tools`, `structuredOutputs`, `promptCaching`, `outputCap`, `pdf`
- Pricing: `promptPer1M`, `completionPer1M`

---

### **8. SETTINGS UPSERT API**

**File:** `/apps/web/app/api/admin/settings/route.ts`

```typescript
// POST /api/admin/settings
```

**Request body:**

```typescript
{
  key: string;           // e.g. 'default_extraction_route'
  value: unknown;        // e.g. 'vertex_gemini_2_5_flash_extraction_primary' or 'vertex/gemini-2.5-flash'
  description?: string;  // optional metadata
}
```

**Implementation** (lines 50-70):

```typescript
const [row] = await db
  .insert(settings)
  .values({
    key: body.key,
    value: body.value,
    ...(body.description !== undefined ? { description: body.description } : {}),
  })
  .onConflictDoUpdate({
    target: settings.key,
    set: {
      value: body.value,
      updatedAt: new Date(),
      ...(body.description !== undefined ? { description: body.description } : {}),
    },
  })
  .returning();
```

Uses Drizzle's `onConflictDoUpdate()` to upsert by primary key `settings.key`.

---

### **9. VISION CAPABILITY DETECTION**

**File:** `/packages/ai/src/routes/types.ts` (line 104)

```typescript
export interface OracleModelRoute {
  supportsVision: boolean;
  // ...
}
```

**Catalog examples:**
- All 6 production routes have `supportsVision: true`
- Internal `vertex_gemini_2_5_flash_lite_message_triage` has `supportsVision: false`

**Stage requirements** (in `/apps/web/lib/stage-requirements.ts`):

```typescript
export const STAGE_REQUIREMENTS: Record<Stage, StageRequirement[]> = {
  interview: [
    CAP_REQ('tools'),
    CAP_REQ('structuredOutputs'),
    CAP_REQ('vision'),  // ← interview REQUIRES vision
    CTX_REQ(100_000),
  ],
  extraction: [
    CAP_REQ('structuredOutputs'),
    CAP_REQ('vision'),  // ← extraction REQUIRES vision
    CTX_REQ(100_000),
  ],
  synthesis: [
    CTX_REQ(400_000),
    CAP_REQ('structuredOutputs'),
    CAP_REQ('thinking'),
    CAP_REQ('outputCap'),
    // synthesis does NOT require vision
  ],
};
```

**To enumerate vision-capable routes:**

```typescript
const visionRoutes = Object.values(ORACLE_MODEL_ROUTES).filter(r => r.supportsVision && r.role === 'extraction');
```

---

### **10. GOOGLE/VERTEX CREDENTIALS**

**File:** `/.env.example` (lines 27-42)

```bash
GOOGLE_CLOUD_PROJECT=
GOOGLE_CLOUD_LOCATION=us-central1
GOOGLE_APPLICATION_CREDENTIALS_JSON=  # Service-account JSON (single line, base64 or raw JSON)
GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET=
GOOGLE_VERTEX_CONTEXT_CACHE_GCS_PREFIX=oracle-context-cache
GOOGLE_VERTEX_BATCH_GCS_BUCKET=
GOOGLE_VERTEX_BATCH_GCS_PREFIX=oracle-batch
```

**Confirms:**
- System ALREADY uses Vertex/Gemini for extraction (`vertex_gemini_2_5_flash_extraction_primary` is the primary)
- Google credentials are fully configured
- GCS buckets are optional (only needed for large context caches and batch prediction)

**Used in adapters:** `/packages/ai/src/providers/vertex-gemini-adapter.ts` reads these env vars

---

### **11. CURRENT HARDCODED DEFAULTS**

**File:** `/packages/ai/src/routes/defaults.ts` (lines 22-26)

```typescript
export const DEFAULT_ORACLE_ROUTES: Record<OracleModelRole, string> = {
  interview: anthropic_claude_haiku_4_5_interview_primary.routeId,
  extraction: vertex_gemini_2_5_flash_extraction_primary.routeId,
  synthesis: anthropic_claude_3_5_sonnet_synthesis_primary.routeId,
};
```

**Fallback in workers:** Workers read from settings first, then fall back to these if unset/unresolvable.
Example in `/apps/workers/src/trigger/claim-extraction.ts` (line 77):

```typescript
const FALLBACK_ROUTE_ID = 'vertex_gemini_2_5_flash_extraction_primary';
```

---

### **12. USAGE IN WORKERS**

**File:** `/apps/workers/src/trigger/claim-extraction.ts` (lines 915-924)

```typescript
const resolved = await resolveRouteFromSettings(db, 'extraction');

const fallback = getOracleRoute(FALLBACK_ROUTE_ID);
if (!resolved && !fallback) {
  throw new Error(
    `[claim-extraction] default_extraction_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
  );
}
const route = resolved ?? fallback;
```

**Pattern for all workers:**
1. Call `resolveRouteFromSettings(db, role)` to read settings + reasoning effort
2. Fall back to a hardcoded route if settings returns null
3. Pass the resolved route to `OracleAIClient.invoke()` for actual inference

