/**
 * resolveRouteFromSettings() — DRY helper for workers and the chat route.
 *
 * Reads both the role's model setting (default_${role}_route) AND the role's
 * reasoning-effort setting (default_${role}_reasoning_effort) in one query,
 * then hands the pair to resolveModelRoute() so the returned OracleModelRoute
 * already has `reasoningEffort` attached.
 *
 * Returns null when the model setting is unset or unparseable — callers should
 * fall back to a hardcoded route (typically the curated catalog primary for
 * the role).
 */

import { inArray } from 'drizzle-orm';
import type { OracleDb } from '@oracle/db';
import { settings } from '@oracle/db/schema';
import { ROUTE_SETTING_KEYS, REASONING_EFFORT_SETTING_KEYS } from './defaults';
import { resolveModelRoute } from './resolve';
import type { OracleModelRole, OracleModelRoute, ReasoningEffort } from './types';

function isReasoningEffort(v: unknown): v is ReasoningEffort {
  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
}

export async function resolveRouteFromSettings(
  db: OracleDb,
  role: OracleModelRole,
): Promise<OracleModelRoute | null> {
  const routeKey = ROUTE_SETTING_KEYS[role];
  const effortKey = REASONING_EFFORT_SETTING_KEYS[role];

  const rows = await db
    .select({ key: settings.key, value: settings.value })
    .from(settings)
    .where(inArray(settings.key, [routeKey, effortKey]));

  const routeRow = rows.find((r) => r.key === routeKey);
  const effortRow = rows.find((r) => r.key === effortKey);

  const modelIdOrRouteId =
    typeof routeRow?.value === 'string' ? routeRow.value : null;
  if (!modelIdOrRouteId) return null;

  const effort: ReasoningEffort | undefined = isReasoningEffort(effortRow?.value)
    ? effortRow.value
    : undefined;

  return resolveModelRoute(modelIdOrRouteId, role, effort);
}

/**
 * Dynamic model route resolver — P1 #1 (Settings overhaul).
 *
 * Handles two ID formats:
 *   1. Catalog routeId  — e.g. "anthropic_claude_haiku_4_5_interview_primary"
 *      → direct lookup in the curated catalog.
 *   2. OpenRouter model ID — e.g. "anthropic/claude-haiku-4-5"
 *      → find the best-matching catalog route for the requested role,
 *        or synthesise a minimal route so the OracleAIClient can dispatch.
 *
 * Workers and routes that previously called getOracleRoute() should call
 * resolveModelRoute() instead so that settings saved via the model-pool
 * picker continue to work even when the saved value is an OpenRouter model ID.
 */

import type { OracleModelRole, OracleModelRoute, OracleProvider, ReasoningEffort } from './types';
import { ORACLE_MODEL_ROUTES } from './catalog';
import { getOracleRoute } from './catalog';

// ---------------------------------------------------------------------------
// Provider-prefix mapping (OpenRouter prefix → Oracle provider name).
// ---------------------------------------------------------------------------

const OR_PROVIDER_MAP: Record<string, OracleProvider> = {
  anthropic: 'anthropic',
  openai: 'openai',
  google: 'vertex',   // OpenRouter uses google/ for Gemini models
  deepseek: 'deepseek',
  qwen: 'qwen',
  // others (meta-llama, mistralai, etc.) are not supported — return null
};

/** Map an OpenRouter provider prefix to the internal OracleProvider enum value. */
function mapPrefix(prefix: string): OracleProvider | null {
  return (OR_PROVIDER_MAP[prefix] ?? null) as OracleProvider | null;
}

// ---------------------------------------------------------------------------
// Default capabilities for synthetic routes — conservative but broad.
// ---------------------------------------------------------------------------

const SYNTHETIC_CAPS: Pick<
  OracleModelRoute,
  | 'supportsVision'
  | 'supportsStreaming'
  | 'supportsToolCalling'
  | 'supportsStructuredOutput'
  | 'supportsReasoningControls'
  | 'costTier'
  | 'fallbackRouteId'
  | 'fallbackCondition'
  | 'enabled'
> = {
  supportsVision: true,
  supportsStreaming: true,
  supportsToolCalling: true,
  supportsStructuredOutput: true,
  supportsReasoningControls: false,
  costTier: 'balanced_default',
  fallbackRouteId: null,
  fallbackCondition: 'not_applicable',
  enabled: true,
};

/** Build a synthetic OracleModelRoute for a model not in the curated catalog. */
function makeSyntheticRoute(
  openRouterId: string,    // e.g. "anthropic/claude-haiku-4-5"
  provider: OracleProvider,
  modelId: string,         // e.g. "claude-haiku-4-5"
  role: OracleModelRole,
): OracleModelRoute {
  const cacheStrategy =
    provider === 'anthropic'
      ? 'anthropic_auto_plus_explicit'
      : provider === 'vertex'
      ? 'vertex_implicit_or_explicit_by_context_size'
      : provider === 'deepseek'
      ? 'deepseek_automatic_prefix'
      : provider === 'qwen'
      ? 'qwen_explicit_context_cache'
      : 'openai_automatic_with_cache_key';

  // DeepSeek and Qwen via OpenAI-compat don't expose strict json_schema mode.
  // OpenAI does. Vertex Gemini supports native json schema. Anthropic uses tool_call.
  const structuredOutputStrategy =
    provider === 'vertex' ? 'native_json_schema'
      : provider === 'openai' ? 'native_json_schema'
      : 'tool_call';

  return {
    routeId: openRouterId,  // use the OpenRouter ID as the routeId
    role,
    tier: 'primary',
    internalPurpose: null,
    provider,
    modelId,
    displayName: openRouterId,
    recommendedUse: `Dynamically resolved from model pool (${openRouterId}).`,
    cacheStrategy,
    structuredOutputStrategy,
    ...SYNTHETIC_CAPS,
  };
}

// ---------------------------------------------------------------------------
// Public resolver
// ---------------------------------------------------------------------------

/**
 * Resolve a model setting value to an OracleModelRoute.
 *
 * Accepts either:
 *   - A catalog routeId      ("anthropic_claude_haiku_4_5_interview_primary")
 *   - An OpenRouter model ID ("anthropic/claude-haiku-4-5")
 *
 * Returns null when the value cannot be resolved to a supported provider.
 * Callers should log a warning and fall back to the default route for the role.
 *
 * @param modelIdOrRouteId  The value stored in the settings table.
 * @param role              The model role being resolved (used when creating
 *                          synthetic routes and for catalog matching).
 */
export function resolveModelRoute(
  modelIdOrRouteId: string,
  role: OracleModelRole,
  reasoningEffort?: ReasoningEffort,
): OracleModelRoute | null {
  let base: OracleModelRoute | null = null;

  // ── 1. Try direct catalog routeId lookup ─────────────────────────────────
  const byRouteId = getOracleRoute(modelIdOrRouteId);
  if (byRouteId) {
    base = byRouteId;
  } else {
    // ── 2. Parse as OpenRouter-style "provider/model" ────────────────────────
    const slashIdx = modelIdOrRouteId.indexOf('/');
    if (slashIdx === -1) return null; // unknown format

    const prefix = modelIdOrRouteId.slice(0, slashIdx);
    const modelId = modelIdOrRouteId.slice(slashIdx + 1);
    const provider = mapPrefix(prefix);
    if (!provider) return null; // unsupported provider prefix

    // ── 3. Try catalog lookup by provider + modelId + role ─────────────────
    const catalogMatch = Object.values(ORACLE_MODEL_ROUTES).find(
      (r) => r.provider === provider && r.modelId === modelId && r.role === role,
    );
    base = catalogMatch ?? makeSyntheticRoute(modelIdOrRouteId, provider, modelId, role);
  }

  // Attach the effort (immutable copy) when provided. Adapters read this off
  // the route at inference time and translate to provider-native format.
  if (reasoningEffort) {
    return { ...base, reasoningEffort };
  }
  return base;
}

// Admin → Settings tab.
// Reads all model + reasoning-effort settings from the DB server-side, passes
// to client pickers. Per-stage required-capability icons rendered from the
// shared @/lib/stage-requirements module so they match the model-pool page.

import React from 'react';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { inArray } from 'drizzle-orm';
import { getDirectDb } from '@oracle/db/client';
import { settings } from '@oracle/db/schema';
import {
  GENERAL_PURPOSE_ROUTE_SETTING_KEY,
  REASONING_EFFORT_SETTING_KEYS,
  ROUTE_SETTING_KEYS,
} from '@oracle/ai';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { ModelPicker, type ReasoningEffort } from './_components/model-picker';
import { DispatchModeToggle, type DispatchMode } from './_components/dispatch-mode-toggle';
import { TeamsLiveBotCard } from './_components/teams-live-bot-card';
import { STAGE_REQUIREMENTS, type Stage } from '@/lib/stage-requirements';

const EXTRACTION_DISPATCH_MODE_KEY = 'extraction_dispatch_mode';

// ---------------------------------------------------------------------------
// Per-stage requirement icons — server component, no 'use client'.
// Pulls the same predicates the picker uses for filtering.
// ---------------------------------------------------------------------------

function StageRequirementIcons({ stage }: { stage: Stage }) {
  const reqs = STAGE_REQUIREMENTS[stage];
  return (
    <div className="flex flex-wrap items-center gap-2.5 mt-3">
      {reqs.map((r, i) => (
        <span
          key={i}
          title={r.label}
          className="flex items-center gap-1 text-xs font-medium text-muted-foreground"
        >
          <r.icon className={cn('size-3.5', r.color)} />
          {r.label}
        </span>
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// The four configurable model roles (3 stages + general-purpose).
// ---------------------------------------------------------------------------

interface RoleDef {
  settingKey: string;
  /** null for general-purpose — has no stage requirements. */
  stage: Stage | null;
  effortSettingKey?: string;
  effortSettingDescription?: string;
  title: string;
  subtitle: string;
  description: React.ReactNode;
  settingDescription: string;
}

const MODEL_ROLES: RoleDef[] = [
  {
    settingKey: ROUTE_SETTING_KEYS.interview,
    stage: 'interview',
    effortSettingKey: REASONING_EFFORT_SETTING_KEYS.interview,
    effortSettingDescription: 'Reasoning effort for the Interview stage. Translated per provider at inference time.',
    title: 'Interview model',
    subtitle: 'Real-time Oracle chat',
    description: (
      <>
        Called synchronously every time an employee sends a message. The employee
        is watching a &ldquo;thinking…&rdquo; indicator. This model must support{' '}
        <strong>tool use</strong> and follow strict one-question-per-reply output
        rules. Employees regularly share images (product photos, diagrams) and
        upload documents — <strong>vision</strong> and a long enough{' '}
        <strong>context window</strong> are both required. Latency is user-facing —
        aim for under 8 s including tool calls.
      </>
    ),
    settingDescription: 'Direct-provider model for real-time Oracle interview chat.',
  },
  {
    settingKey: ROUTE_SETTING_KEYS.extraction,
    stage: 'extraction',
    effortSettingKey: REASONING_EFFORT_SETTING_KEYS.extraction,
    effortSettingDescription: 'Reasoning effort for async claim extraction. Higher = better recall at higher cost.',
    title: 'Extraction model',
    subtitle: 'Async claim extraction from messages & documents',
    description: (
      <>
        Runs in the background every 4 hours (and on document upload) via
        Trigger.dev. Reads batches of employee messages or document chunks and
        outputs structured JSON: claim type, summary, impact score, confidence
        score, exact supporting quote, knowledge domains, and suggested gaps.
        Nobody is waiting — optimise for <strong>accuracy</strong> and{' '}
        <strong>structured output reliability</strong>. Reasoning models with
        non-zero effort generally improve quality of impact / confidence scoring.
      </>
    ),
    settingDescription: 'Direct-provider model for async claim extraction from messages and documents.',
  },
  {
    settingKey: ROUTE_SETTING_KEYS.synthesis,
    stage: 'synthesis',
    effortSettingKey: REASONING_EFFORT_SETTING_KEYS.synthesis,
    effortSettingDescription: 'Reasoning effort for brain synthesis. High effort recommended for contradiction reasoning.',
    title: 'Synthesis model',
    subtitle: 'Periodic Brain section synthesis',
    description: (
      <>
        Runs on a weekly schedule and on admin trigger. Reads up to 200 approved
        claims per brain section and synthesizes a new versioned Markdown
        document where <em>every paragraph maps to approved claim IDs</em>. The
        output is validated by a backend rule engine — any hallucinated or
        untracked claim ID causes the run to fail. This model must handle{' '}
        <strong>very long context</strong>, produce{' '}
        <strong>structured JSON</strong>, and reason carefully about
        contradicting evidence. No latency requirement.
      </>
    ),
    settingDescription: 'Direct-provider model for brain section synthesis — long-context, structured output.',
  },
  {
    settingKey: GENERAL_PURPOSE_ROUTE_SETTING_KEY,
    stage: null,
    title: 'General-purpose model',
    subtitle: 'Utility / fallback model for internal jobs',
    description: (
      <>
        Used for one-off internal tasks that don&apos;t fit the three stages
        above — taxonomy cluster naming, on-demand classification, ad-hoc
        admin queries. Pick whatever the current best general-purpose model
        is and update it here when a newer one ships. The picker draws from
        the full discovered catalog (no pool or stage requirements apply).
      </>
    ),
    settingDescription: 'General-purpose / utility model. Admin updates this when a newer model is available.',
  },
];

// ---------------------------------------------------------------------------
// Page
// ---------------------------------------------------------------------------

function isReasoningEffort(v: unknown): v is ReasoningEffort {
  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
}

export default async function AdminSettingsPage() {
  const db = getDirectDb();

  // Build the full list of settings keys we need to read — both model + effort + dispatch mode.
  const allKeys: string[] = [
    ...MODEL_ROLES.flatMap((r) =>
      r.effortSettingKey ? [r.settingKey, r.effortSettingKey] : [r.settingKey],
    ),
    EXTRACTION_DISPATCH_MODE_KEY,
  ];

  const rows = await db.select().from(settings).where(inArray(settings.key, allKeys));

  // Build lookup so we can pass the right current values to each picker.
  const currentValues: Record<string, unknown> = {};
  for (const row of rows) currentValues[row.key] = row.value;

  const rawDispatchMode = currentValues[EXTRACTION_DISPATCH_MODE_KEY];
  const dispatchMode: DispatchMode = rawDispatchMode === 'batch' ? 'batch' : 'sync';

  return (
    <div className="space-y-8">
      <header className="space-y-2">
        <h1 className="text-2xl font-semibold">Settings</h1>
        <p className="text-sm text-muted-foreground">
          Model configuration for all Oracle tasks. Each role has different
          capability and performance requirements — see descriptions below.
          Changes take effect on the next run of that task.
        </p>
        <p className="text-sm text-muted-foreground">
          The pickers below show models from your{' '}
          <Link
            href="/admin/settings/model-pool"
            className="underline underline-offset-2 text-foreground hover:text-foreground/70"
          >
            model pool
          </Link>
          . Stage requirements (capability flags + context-window thresholds)
          are enforced both here and on the pool page — they share the same
          source of truth.
        </p>
      </header>

      <Card className="max-w-2xl">
        <CardHeader>
          <CardTitle className="text-base">Live Teams meeting bot</CardTitle>
          <CardDescription className="font-medium text-foreground/70">
            Bring Oracle into a meeting
          </CardDescription>
          <p className="text-sm text-muted-foreground mt-1">
            Oracle does not appear in the Microsoft Teams people picker yet.
            Paste a Teams meeting link here and Recall.ai will bring Oracle
            into the call as a bot participant.
          </p>
        </CardHeader>
        <CardContent>
          <TeamsLiveBotCard />
        </CardContent>
      </Card>

      {MODEL_ROLES.map((role) => {
        const currentModel =
          typeof currentValues[role.settingKey] === 'string'
            ? (currentValues[role.settingKey] as string)
            : null;
        const rawEffort = role.effortSettingKey ? currentValues[role.effortSettingKey] : null;
        const currentEffort: ReasoningEffort | null = isReasoningEffort(rawEffort) ? rawEffort : null;

        const card = (
          <Card key={role.settingKey} className="max-w-2xl">
            <CardHeader>
              <CardTitle className="text-base">{role.title}</CardTitle>
              <CardDescription className="font-medium text-foreground/70">
                {role.subtitle}
              </CardDescription>
              <p className="text-sm text-muted-foreground mt-1">
                {role.description}
              </p>
              {role.stage && <StageRequirementIcons stage={role.stage} />}
            </CardHeader>
            <CardContent>
              <ModelPicker
                currentModel={currentModel}
                currentEffort={currentEffort}
                settingKey={role.settingKey}
                settingDescription={role.settingDescription}
                effortSettingKey={role.effortSettingKey}
                effortSettingDescription={role.effortSettingDescription}
              />
            </CardContent>
          </Card>
        );

        // After the Extraction card, inject the dispatch-mode toggle card —
        // it controls how the extraction worker dispatches (sync vs Batch API).
        if (role.stage === 'extraction') {
          return (
            <div key={role.settingKey} className="space-y-8">
              {card}
              <Card className="max-w-2xl">
                <CardHeader>
                  <CardTitle className="text-base">Extraction dispatch mode</CardTitle>
                  <CardDescription className="font-medium text-foreground/70">
                    Sync API vs provider Batch API
                  </CardDescription>
                  <p className="text-sm text-muted-foreground mt-1">
                    The Batch API runs claim extraction asynchronously at about 50% off
                    the sync price with a 24-hour SLA. Within a chat session the Oracle
                    still reads live message history, so conversation quality is
                    unchanged — only cross-session knowledge freshness drops by up to
                    24 hours. See <strong>DECISIONS.md D14</strong> for the full
                    trade-off analysis.
                  </p>
                </CardHeader>
                <CardContent>
                  <DispatchModeToggle currentMode={dispatchMode} />
                </CardContent>
              </Card>
            </div>
          );
        }

        return card;
      })}
    </div>
  );
}

