 * format the image part for the chosen model.
 */
export async function resolveVisionRouteFromSettings(
  db: OracleDb,
): Promise<OracleModelRoute | null> {
  const rows = await db
    .select({ key: settings.key, value: settings.value })
    .from(settings)
    .where(inArray(settings.key, [VISION_ROUTE_SETTING_KEY, VISION_REASONING_EFFORT_SETTING_KEY]));

  const routeRow = rows.find((r) => r.key === VISION_ROUTE_SETTING_KEY);
  const effortRow = rows.find((r) => r.key === VISION_REASONING_EFFORT_SETTING_KEY);

  const modelIdOrRouteId =
    typeof routeRow?.value === 'string' ? routeRow.value : null;
  if (!modelIdOrRouteId) return null;

  const effort: ReasoningEffort | undefined = isReasoningEffort(effortRow?.value)
    ? effortRow.value
    : undefined;

